#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        long long fearfulness = 1;
        for (int i = N - 1; i >= 0; i--) {
            int juniorIndex = -1;
            for (int j = i - 1; j >= 0; j--) {
                if (A[j] < A[i]) {
                    juniorIndex = j;
                    break;
                }
            }
            if (juniorIndex == -1) {
                fearfulness = (fearfulness * 1) % MOD;
            } else {
                fearfulness = (fearfulness * (i - juniorIndex + 1)) % MOD;
            }
        }
        printf("%lld\n", fearfulness);
    }
    return 0;
}

